section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/multi-platform-design-parity.json",
  "title": "Multi-Platform Design Parity",
  "type": "object",
  "required": [
    "artefact_id",
    "feature_id",
    "surfaces",
    "token_map",
    "gesture_map",
    "density_tiers",
    "platform_overrides",
    "parity_score",
    "drift_log",
    "evidence",
    "status",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "feature_id": {
      "type": "string",
      "description": "feature_id",
      "minLength": 1
    },
    "surfaces": {
      "type": "array",
      "description": "surfaces (array)",
      "minItems": 1
    },
    "token_map": {
      "type": "string",
      "description": "token_map",
      "minLength": 1
    },
    "gesture_map": {
      "type": "string",
      "description": "gesture_map",
      "minLength": 1
    },
    "density_tiers": {
      "type": "array",
      "description": "density_tiers (array)",
      "minItems": 1
    },
    "platform_overrides": {
      "type": "array",
      "description": "platform_overrides (array)",
      "minItems": 1
    },
    "parity_score": {
      "type": "number",
      "description": "parity_score (numeric)"
    },
    "drift_log": {
      "type": "array",
      "description": "drift_log (array)",
      "minItems": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}
